parameters.body:
={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are an AI configuration assistant. Extract business hours, routing rules, and emergency definitions from the provided call transcript. Output your response strictly as a JSON object."
    },
    {
      "role": "user",
      "content": "{{ $json.clean_transcript }}"
    }
  ],
  "response_format": {
    "type": "json_object"
  }
}

parameters.jsCode:
try {
  // 1. Get raw content from Groq
  const rawContent = $input.first().json.choices[0].message.content;
  const groqOutput = JSON.parse(rawContent);

  // 2. Define the Hygiene Rules (Templates)
  const businessHoursRule = "Greeting -> Ask purpose -> Collect name/number -> Transfer -> Fallback if fail -> Ask if anything else -> Close. Do not mention 'function calls' to the caller.";
  const afterHoursRule = "Greeting -> Ask purpose -> Confirm emergency -> If emergency: collect name, number, address immediately -> Transfer -> Fallback -> Ask if anything else -> Close. Do not mention 'function calls' to the caller.";

  // 3. Construct the structures
  const accountMemo = {
    business_hours: groqOutput.business_hours,
    routing_rules: groqOutput.routing_rules,
    emergency_definitions: groqOutput.emergency_definitions,
    questions_or_unknowns: groqOutput.questions_or_unknowns || []
  };

  const agentSpec = {
    system_prompt: `You are an assistant for Ben's Electric. 
    DURING BUSINESS HOURS: ${businessHoursRule}
    AFTER HOURS: ${afterHoursRule}`,
    extracted_data: groqOutput
  };

  // 4. Return both as binary
  return {
    json: { success: true },
    binary: {
      memo: {
        data: Buffer.from(JSON.stringify(accountMemo, null, 2)).toString('base64'),
        mimeType: 'application/json',
        fileName: 'memo.json'
      },
      spec: {
        data: Buffer.from(JSON.stringify(agentSpec, null, 2)).toString('base64'),
        mimeType: 'application/json',
        fileName: 'agent_spec.json'
      }
    }
  };

} catch (error) {
  // 5. RELIABILITY CHECK: Handle failures and save an error log
  const errorLog = {
    timestamp: new Date().toISOString(),
    message: error.message,
    input_received: $input.first().json
  };

  return {
    json: { success: false, error: error.message },
    binary: {
      error_log: {
        data: Buffer.from(JSON.stringify(errorLog, null, 2)).toString('base64'),
        mimeType: 'application/json',
        fileName: 'error_log.json'
      }
    }
  };
}

let rawText = $input.first().json.transcript;

let cleanText = rawText.replace(/[\r\n]+/g, " ");

if (cleanText.length > 15000) {
    cleanText = cleanText.substring(0, 15000) + "... (truncated)";
}

return {
  clean_transcript: cleanText
};
